import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { FiLock, FiUser } from 'react-icons/fi';

const Login = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await login(username, password);
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Please check credentials.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-logo">
          <h2>OrangeHRM</h2>
          <p style={{ color: '#999', fontSize: 13, marginTop: 4 }}>Human Resource Management</p>
        </div>
        <form onSubmit={handleSubmit}>
          {error && <div className="error-msg">{error}</div>}
          <div className="form-group">
            <label>Username</label>
            <div style={{ display: 'flex', alignItems: 'center', border: '1px solid #e0e0e0', borderRadius: 6, padding: '0 12px' }}>
              <FiUser style={{ color: '#999' }} />
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder="Enter username"
                style={{ border: 'none', padding: '10px 8px', width: '100%' }}
                required
              />
            </div>
          </div>
          <div className="form-group">
            <label>Password</label>
            <div style={{ display: 'flex', alignItems: 'center', border: '1px solid #e0e0e0', borderRadius: 6, padding: '0 12px' }}>
              <FiLock style={{ color: '#999' }} />
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter password"
                style={{ border: 'none', padding: '10px 8px', width: '100%' }}
                required
              />
            </div>
          </div>
          <button className="btn btn-primary btn-block" disabled={loading} style={{ padding: 12, fontSize: 15 }}>
            {loading ? 'Signing in...' : 'Login'}
          </button>
        </form>
        <div className="login-credentials">
          <strong>Demo Credentials:</strong><br />
          Username: <strong>admin</strong> / Password: <strong>admin123</strong>
        </div>
        <div className="login-footer">
          &copy; 2026 OrangeHRM Clone. All rights reserved.
        </div>
      </div>
    </div>
  );
};

export default Login;
